def solution(height):
    max_area = 0
    left, right = 0, len(height) - 1
    while left < right:
        width = right - left
        area = min(height[left], height[right]) * width
        max_area = max(max_area, area)
        if height[left] < height[right]:
            left += 1
        else:
            right -= 1
    return max_area

def solution(coins, amount):
    dp = [float('inf')] * (amount + 1)
    dp[0] = 0
    for i in range(1, amount + 1):
        for coin in coins:
            if coin <= i:
                dp[i] = min(dp[i], dp[i - coin] + 1)
    return dp[amount] if dp[amount] != float('inf') else -1

def solution(grid):
    if not grid:
        return 0
    count = 0
    def dfs(i, j):
        if i < 0 or i >= len(grid) or j < 0 or j >= len(grid[0]) or grid[i][j] == '0':
            return
        grid[i][j] = '0'
        dfs(i + 1, j)
        dfs(i - 1, j)
        dfs(i, j + 1)
        dfs(i, j - 1)
    for i in range(len(grid)):
        for j in range(len(grid[0])):
            if grid[i][j] == '1':
                dfs(i, j)
                count += 1
    return count

def solution(beginWord, endWord, wordList):
    def neighbors(word):
        result = []
        for w in wordList:
            if len(w) == len(word) and sum(1 for i in range(len(w)) if w[i] != word[i]) == 1:
                result.append(w)
        return result

    from collections import defaultdict, deque
    neighbors_map = defaultdict(list)
    for word in wordList:
        neighbors_map[word] = neighbors(word)

    parents = defaultdict(list)
    visited = {beginWord}
    queue = deque([beginWord])
    found = False

    while queue and not found:
        for _ in range(len(queue)):
            word = queue.popleft()
            for neighbor in neighbors_map[word]:
                if neighbor == endWord:
                    found = True
                    parents[neighbor].append(word)
                elif neighbor not in visited:
                    parents[neighbor].append(word)
                    visited.add(neighbor)
                    queue.append(neighbor)

    def backtrack(word, path):
        if word == beginWord:
            return [[beginWord] + path]
        result = []
        for parent in parents[word]:
            result.extend(backtrack(parent, [word] + path))
        return result

    return backtrack(endWord, []) if found else []

def solution(s, p):
    memo = {}
    def dp(i, j):
        if (i, j) in memo:
            return memo[(i, j)]
        if j == len(p):
            return i == len(s)
        first_match = i < len(s) and p[j] in {s[i], '.'}
        if j + 1 < len(p) and p[j + 1] == '*':
            ans = dp(i, j + 2) or (first_match and dp(i + 1, j))
        else:
            ans = first_match and dp(i + 1, j + 1)
        memo[(i, j)] = ans
        return ans
    return dp(0, 0)
